window.__QUIZ_DATA__=[{"id":"objective>Civic Education>2020>1","subject":"Civic Education","year":"2020","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF NATIONALISM","question":"Nationalism in Nigeria eventually led to","images":[],"options":{"A":"national renaissance","B":"creattion of states","C":"decolonization","D":"the end of the military rule"},"answer":"C","explanation":"Nationalism is a political ideology that involves a strong identification of a group of individuals with a nation. In the context of Nigeria, nationalism was a significant force for the struggle for independence from British rule. Therefore, nationalism in Nigeria eventually led to decolonization, not the end of military rule, national renaissance, or creation of states.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>2","subject":"Civic Education","year":"2020","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS","question":"Which of the following conditions gives rise to the denial of right to life?","images":[],"options":{"A":"Homicide","B":"Forgery","C":"Protest","D":"Burglary"},"answer":"A","explanation":"The right to life is a fundamental human right that is protected by law. Homicide, which is the act of one human killing another, directly violates this right. Therefore, it is a condition that gives rise to the denial of the right to life. The other options, Forgery, Protest, and Burglary, while they are crimes, do not directly result in the denial of the right to life.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>3","subject":"Civic Education","year":"2020","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM","question":"Activities that act to clog the wheel of societal progress can be described as","images":[],"options":{"A":"family issues","B":"cultural vices","C":"religious issue","D":"social vices"},"answer":"D","explanation":"Social vices are activities that are considered harmful or undesirable in society. They act to clog the wheel of societal progress because they disrupt social order, cause harm to individuals and communities, and hinder development. Examples of social vices include corruption, crime, and discrimination. The other options, family issues, cultural vices, and religious issues, while they can have negative impacts, are not necessarily activities that clog the wheel of societal progress.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>4","subject":"Civic Education","year":"2020","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT","question":"The four most prominent national leaders of Nigeria at independence were","images":[],"options":{"A":"J.S Tarka, S.L Akintola, Aminu Kano and Ernest Ikoli","B":"Nnamdi Azikwe, K.O Mbadiwe, Arthur Richards and Aminu Kano","C":"Tafawa Balewa, Obafemi Awolowo, Nnamdi Azikwe and Ahmadu Bello","D":"Adesoji Aderemi, Shehu Shagari, Obafemi Awolowo and Nnamdi Azikwe"},"answer":"C","explanation":"The four most prominent national leaders of Nigeria at independence were Tafawa Balewa, Obafemi Awolowo, Nnamdi Azikwe and Ahmadu Bello. These leaders played significant roles in the struggle for Nigeria's independence. Tafawa Balewa was the first Prime Minister of Nigeria, Obafemi Awolowo was the leader of the Action Group and first Premier of the Western Region, Nnamdi Azikwe was the first President of Nigeria and Ahmadu Bello was the first Premier of the Northern Nigeria Region.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>5","subject":"Civic Education","year":"2020","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : MEANING OF RESPONSIBLE PARENTHOOD","question":"Responsible parenthood can complement the activities of government in several ways except by raising","images":[],"options":{"A":"responsible citizens","B":"citizens who oppose the government","C":"responsible future leaders","D":"entrepreneurs in the society"},"answer":"B","explanation":"Responsible parenthood does not involve raising citizens who oppose the government. Responsible parenthood involves raising responsible citizens, future leaders, and entrepreneurs who can contribute positively to the society and the economy. Opposing the government does not necessarily mean being responsible or contributing positively to the society. It could lead to unrest, instability and other negative consequences.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>6","subject":"Civic Education","year":"2020","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE AND ROLES OF CONSTITUTED AUTHORITY","question":"One importance of constituted authority is that it leads to","images":[],"options":{"A":"maintenance of law and order","B":"concentration of power","C":"immunity of elected leaders","D":"arbitrary use of power"},"answer":"A","explanation":"Constituted authority refers to the powers and mechanisms established by a constitution, which govern a state or organization. One of the primary roles of constituted authority is to maintain law and order in the society. It does this by enforcing laws and regulations, and by providing a system for resolving disputes. This helps to ensure that society functions smoothly and that people's rights are protected.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>7","subject":"Civic Education","year":"2020","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : IMPORTANCE OF VALUES TO SOCIETY","question":"Teaching children to be satisfied with what they have is a way of encouraging","images":[],"options":{"A":"self--reliance","B":"orderliness","C":"contentment","D":"selflessness"},"answer":"C","explanation":"Teaching children to be satisfied with what they have is a way of encouraging contentment. Contentment refers to a state of happiness and satisfaction. When children are taught to be satisfied with what they have, they learn to appreciate their possessions and circumstances, and this leads to a sense of contentment. This does not mean they should not aspire for more, but they should not be overly concerned or unhappy if they do not have everything they want.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>8","subject":"Civic Education","year":"2020","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY","question":"Law and order can best be maintained in Nigeria through the","images":[],"options":{"A":"making of decree by the various security agencies","B":"constitutional law enforcement and citizens' common welfare","C":"prohibition of public protest, terrorism and militancy","D":"use of modern security gadgets and directorate of state security service"},"answer":"B","explanation":"Law and order can best be maintained in Nigeria through constitutional law enforcement and citizens' common welfare. This is because the constitution is the supreme law of the land and it provides guidelines for maintaining law and order. It also ensures the common welfare of citizens by protecting their rights and freedoms. The other options do not provide a comprehensive approach to maintaining law and order.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>9","subject":"Civic Education","year":"2020","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING AND HISTORICAL BACKGROUND OF THE UNIVERSAL DECLARATION OF HUMAN RIGHTS (UDHR)","question":"The Universal Declaration of Human Rights(UDHR) was adopted by the","images":[],"options":{"A":"United Nations General Assembly","B":"United National Security Council","C":"United Nations San- Francisco Conference","D":"United Nations Trusteeship Council"},"answer":"A","explanation":"The Universal Declaration of Human Rights (UDHR) was adopted by the United Nations General Assembly. The UDHR is a milestone document in the history of human rights that was proclaimed by the United Nations General Assembly in Paris on 10 December 1948. The other options are incorrect because they are not the bodies that adopted the UDHR.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>10","subject":"Civic Education","year":"2020","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : MEANING OF RESPONSIBLE PARENTHOOD","question":"Responsible parenting is the ability of parents to","images":[],"options":{"A":"provide qualitative education for their children","B":"establish profitable business for the fanily","C":"meet the basic and social needs of their children","D":"ensure that rights of their chidren are safeguarded"},"answer":"C","explanation":"Responsible parenting involves meeting both the basic and social needs of children. Basic needs include food, shelter, and clothing, while social needs involve emotional support, love, and guidance. Providing qualitative education or establishing a profitable business for the family are part of the ways to meet these needs but they are not the definition of responsible parenting. Ensuring the rights of children are safeguarded is also part of responsible parenting but it does not encompass all that responsible parenting entails.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>11","subject":"Civic Education","year":"2020","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : IMPORTANCE OF RULE OF LAW","question":"Use the story below to answer question below:  Amaka stole a chicken from a poultry farm.The workers on the farm caught Amaka and gave him the beatings of his life.    Assuming the offence committed by Amaka in the above story happened in a democratic society,the poultry farm workers would be","images":[],"options":{"A":"honoured for executing instant justice","B":"punished for taking laws into their own hands","C":"converted to security personnel","D":"promoted for safeguarding the poultry farm"},"answer":"B","explanation":"In a democratic society, everyone is subject to the law and no one is allowed to take the law into their own hands. Therefore, the workers would be punished for taking laws into their own hands. Executing instant justice, converting to security personnel, or promoting for safeguarding the poultry farm are not actions that would be taken in a democratic society in response to the workers' actions.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>12","subject":"Civic Education","year":"2020","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : IMPORTANCE OF RULE OF LAW","question":"Use the story below to answer question below:  Amaka stole a chicken from a poultry farm.The workers on the farm caught Amaka and gave him the beatings of his life.  Against the background of democratic society, the farm workers in the story above are expected to","images":[],"options":{"A":"hand Amaka over to the police","B":"deny Amaka his right to fair hearing","C":"judge Amaka after giving him a fair hearing","D":"discharge him of the offence committed"},"answer":"A","explanation":"In a democratic society, the rule of law is paramount. This means that when a crime is committed, the offender should be handed over to the police who are the law enforcement agents. The police will then carry out investigations and if found guilty, the offender will be prosecuted in a court of law. The farm workers do not have the right to take the law into their own hands by beating Amaka. They should have handed him over to the police.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>13","subject":"Civic Education","year":"2020","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : IMPORTANCE OF INTER-COMMUNAL RELATIONSHIPS","question":"A community which does not associate with neighbouring communities would likely experience","images":[],"options":{"A":"limited access to modern facilities","B":"corruption among elected officials","C":"retarded economic development","D":"disregard for constitutional rights"},"answer":"C","explanation":"A community that does not associate with neighbouring communities would likely experience retarded economic development. This is because interaction with other communities often leads to exchange of ideas, trade and other forms of cooperation that can lead to economic growth. Isolation can limit access to new ideas, technologies and opportunities for trade, thereby slowing down economic development.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>14","subject":"Civic Education","year":"2020","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS","question":"Which of the following agencies carries out inspection of vehicles for road worthiness in Nigeria?","images":[],"options":{"A":"Nigeria Security and Civil Defence Corps","B":"The Nigeria Police","C":"Vehicle Inspection Office","D":"Nigeria Customs Services"},"answer":"C","explanation":"The Vehicle Inspection Office (VIO) is the agency responsible for carrying out inspection of vehicles for road worthiness in Nigeria. The VIO ensures that all vehicles on the road are safe and meet the necessary safety standards.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2020>15","subject":"Civic Education","year":"2020","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : ROLES OF RESPONSIBLE PARENTS","question":"The role of a responsible mother is to","images":[],"options":{"A":"ensure good neighbourliness","B":"report the husband when necessary","C":"help the motherless children and orphans","D":"support the father in meeting family needs"},"answer":"D","explanation":"A responsible mother's role is to support the father in meeting family needs. This includes providing emotional, physical, and financial support to the family. This does not exclude other roles like ensuring good neighbourliness or helping the less privileged, but the primary role is to support the family.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2020>16","subject":"Civic Education","year":"2020","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS","question":"The human right that is application to human beings without reference to their nationality is the right to","images":[],"options":{"A":"life and dignity of human persons","B":"vote","C":"acquire asset and landed property","D":"work"},"answer":"A","explanation":"The right to life and dignity of human persons is a fundamental human right that applies to all human beings regardless of their nationality. This right is enshrined in various international human rights instruments, including the Universal Declaration of Human Rights. The other options such as the right to vote, acquire asset and landed property, and work can be subject to certain restrictions based on nationality.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2020>17","subject":"Civic Education","year":"2020","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS","question":"All regulatory road signs can be categorized into","images":[],"options":{"A":"mandatory and mediative","B":"punitive and prohibitive","C":"prohibitive and mandatory","D":"persuasive and informative"},"answer":"C","explanation":"Regulatory road signs are typically categorized into prohibitive and mandatory signs. Prohibitive signs are used to prohibit certain types of maneuvers or some types of traffic. Mandatory signs are used to set the obligations of all traffic that uses a specific area of road. The other options such as punitive and mediative, and persuasive and informative are not standard categories of road signs.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2020>18","subject":"Civic Education","year":"2020","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : IMPORTANCE OF INTER-COMMUNAL RELATIONSHIPS","question":"A healthy inter-communal relationship is not associated with","images":[],"options":{"A":"political development","B":"economic progress","C":"state of violence","D":"social security"},"answer":"C","explanation":"A healthy inter-communal relationship is associated with political development, economic progress, and social security. It promotes peace, unity, and cooperation among different communities, which in turn fosters development in various sectors. However, it is not associated with a state of violence. A state of violence is usually a result of a poor or unhealthy inter-communal relationship, characterized by conflicts, disputes, and misunderstandings.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>19","subject":"Civic Education","year":"2020","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM","question":"Cult activities are usually  characterized by","images":[],"options":{"A":"terrorist activities","B":"despotic tendencies","C":"violent disposition","D":"martial bravery"},"answer":"A","explanation":"Cult activities are usually characterized by terrorist activities. Cults are often associated with violence, intimidation, and other forms of harm to achieve their objectives. They often use terror as a tool to instill fear and exert control. While they may also exhibit despotic tendencies, violent disposition, and martial bravery, the most defining characteristic is their engagement in terrorist activities.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>20","subject":"Civic Education","year":"2020","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : MEANING OF DRUG ABUSE","question":"Which of the following cannot be termed drug abuse?","images":[],"options":{"A":"Using prescribed drugs the wrong way","B":"Drinking alcohol in excess","C":"Frequent intake of soft drinks","D":"The use of self-medication"},"answer":"C","explanation":"Drug abuse refers to the misuse of substances, especially over-the-counter (OTC) medications, prescription drugs, alcohol, and illicit drugs for purposes other than those for which they are indicated or in a manner or in quantities other than directed. Frequent intake of soft drinks does not fall under this category as soft drinks are not classified as drugs.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2020>21","subject":"Civic Education","year":"2020","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : ACHIEVING POPULAR PARTICIPATION IN POLITICS","question":"An interventionist programme between two warring groups can best be made successful through","images":[],"options":{"A":"conciliation","B":"cooperation","C":"mediation","D":"counselling"},"answer":"C","explanation":"Mediation is a process where a neutral third party helps the disputing parties to reach a mutually acceptable solution. In the context of two warring groups, mediation is the most effective interventionist programme as it involves an unbiased mediator who facilitates communication, promotes understanding, assists the parties to identify their needs and interests, and uses creative problem solving techniques to enable the parties to reach their own agreement.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>22","subject":"Civic Education","year":"2020","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : FEATURES OF RULE OF LAW","question":"Use the image in figure 1 to answer question below      The blindfold on the symbol of the woman in Figure 1 indicates that laws must be applied","images":["data:image/png;base64,"],"options":{"A":"with great caution","B":"in favour of women","C":"with mental mindset","D":"by an anonymous judge"},"answer":"A","explanation":"The blindfold represents impartiality, the ideal that justice should be applied without regard to wealth,power or other status.","marks":"1","difficulty":"3"},{"id":"objective>Civic Education>2020>23","subject":"Civic Education","year":"2020","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : CAUSES OF HIV/AIDS","question":"Which of these cannot be responsible for the spread of Human Immune deficiency Virus? Acquired Immune Deficiency Syndrome (HIV/AIDS)?","images":[],"options":{"A":"Unprotected sexual intercourse","B":"Dinning and drinking with people living with HIV/AIDS","C":"Using unscreened blood transfusion","D":"Sharing of unsterilized piercing instruments"},"answer":"B","explanation":"HIV/AIDS cannot be spread through casual contact such as dining and drinking with people living with the virus. HIV is transmitted through direct contact with certain body fluids from a person with HIV. These body fluids include blood, semen, vaginal fluids, and breast milk. It is not transmitted through saliva, sweat, tears, urine, or feces.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>24","subject":"Civic Education","year":"2020","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : WAYS OF PREVENTING CULTISM IN SOCIETY","question":"Studying hard in school is one of the preventive measures against","images":[],"options":{"A":"unionism","B":"cultism","C":"bigotry","D":"racism"},"answer":"B","explanation":"Studying hard in school can be seen as a preventive measure against cultism. Cultism often involves engaging in activities that are outside the normal academic curriculum. Therefore, focusing on academic work and studying hard can help prevent students from being lured into cult activities. Cultism refers to the practices and rituals followed by a cult, often involving violent or illegal activities.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2020>25","subject":"Civic Education","year":"2020","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : STIGMATIZATION OF PEOPLE LIVING WITH HIV/AIDS","question":"Use the dialogue below to answer question below:  Zainab: Mum, i am afraid.  Mum: Afraid of what?  Zainab: Lucy,the girl with HIV/AIDS in my class hugged me in school today.  Mum: Dont worry dear, you can't contact HIV by mere hugging.Cheer up my daughter.    From the dialogue above, the problem of Zainab is that of","images":[],"options":{"A":"stigmatization","B":"ignorance","C":"infection","D":"pride"},"answer":"B","explanation":"From the dialogue, Zainab's problem is ignorance. She is afraid because she thinks she can contract HIV/AIDS from hugging someone who is infected. This shows a lack of knowledge or understanding about how the disease is transmitted. HIV/AIDS is not transmitted through casual contact such as hugging, shaking hands, or sharing personal objects, food or water. It is transmitted through certain body fluids\u2014blood, semen, pre-seminal fluid, rectal fluids, vaginal fluids, and breast milk\u2014from a person who has HIV.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>26","subject":"Civic Education","year":"2020","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : PROBLEMS OF CIVIL SOCIETY; I.E. BRIBERY AND CORRUPTION, INADEQUATE FUNDING, THE OVERBEARING INFLUENCE OF FOREIGN DONORS ETC","question":"A major challenge for civil societies in executing their mandate is","images":[],"options":{"A":"poor funding of their programme","B":"questionable reputable of their members","C":"compostion of their leadership","D":"their desire for political power"},"answer":"A","explanation":"Civil societies often face the challenge of poor funding of their programmes. This is because they rely on donations, grants, and contributions from members and well-wishers to fund their activities. When these sources of funds are not forthcoming, it becomes difficult for them to execute their mandate effectively. The other options do not directly affect the execution of their mandate as much as funding does.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>27","subject":"Civic Education","year":"2020","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFORTS OF GOVERNMENT AND INDIVIDUALS IN STOPPING HUMAN TRAFFICKING","question":"The National Agency for the prohibtion of Traffickig in Persons (NAPTIP) was established in the year","images":[],"options":{"A":"2001","B":"2002","C":"2003","D":"2004"},"answer":"C","explanation":"The National Agency for the Prohibition of Trafficking in Persons (NAPTIP) is a law enforcement agency in Nigeria. It was established by the Trafficking in Persons (Prohibition) Enforcement and Administration Act, 2003. The agency is charged with enforcing laws against human trafficking and similar human rights violations.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2020>28","subject":"Civic Education","year":"2020","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT","question":"The Senator and House of Representative in Nigeria constitutue the","images":[],"options":{"A":"Federal congress","B":"National Parliament","C":"Federal Legislature","D":"National Assembly"},"answer":"D","explanation":"In Nigeria, the bicameral legislature consists of the House of Representatives and the Senate, and together they make up the National Assembly. The National Assembly is the highest legislative body in the country and has the power to make laws for the peace, order, and good governance of the Federation.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2020>29","subject":"Civic Education","year":"2020","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFECTS AND CONSEQUENCES OF HUMAN TRAFFICKING","question":"A primary ambition of individuals involved in human trafficking that cannot be achieved is","images":[],"options":{"A":"unwanted pregnancy","B":"physical and actual abuse","C":"functional freedom","D":"depression and suicidal thought"},"answer":"C","explanation":"Human trafficking involves the use of force, fraud, or coercion to obtain some type of labor or commercial sex act. The primary ambition of individuals involved in human trafficking is to exploit others for personal or financial gain. Functional freedom, which refers to the ability to make decisions and act independently, cannot be achieved by those involved in human trafficking because their actions are illegal and infringe upon the rights and freedoms of others.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>30","subject":"Civic Education","year":"2020","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : FUNCTIONS OF GOVERNMENT","question":"The approval of the government budget is the responsibility of the","images":[],"options":{"A":"judiciary","B":"legislature","C":"ministers","D":"executive"},"answer":"B","explanation":"The approval of the government budget is the responsibility of the legislature. In a democratic system of government, the legislature is the branch of government that has the power to make laws, and also has the responsibility of approving the government's budget. This is to ensure checks and balances, and to prevent misuse of public funds by the executive branch.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2020>31","subject":"Civic Education","year":"2020","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : EFFORTS OF GOVERNMENT TOWARDS YOUTH EMPOWERMENT","question":"Use the dialogue below to answer question below:  Bayo: Wao! Shola, how did you manage to purchase a new tricycle?  Shola: I did not buy it, it was the Councillor from my town that distributed tricycles to unemployed youths. I am lucky to be one of them.  Bayo: Congratulation! That's a good gesture. I wish the Councillor from my town would do same.    The step taken by the Councillor in the dialogue above is best described as","images":[],"options":{"A":"empowerment","B":"selflessness","C":"development","D":"patriotism"},"answer":"A","explanation":"The Councillor's action of distributing tricycles to unemployed youths is a form of empowerment. Empowerment in this context refers to the process of increasing the capacity of individuals or groups to make choices and to transform those choices into desired actions and outcomes. By providing tricycles, the Councillor is enabling the youths to have a means of livelihood, thus empowering them.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>32","subject":"Civic Education","year":"2020","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : YOUTH EMPOWERMENT SKILLS","question":"Use the dialogue below to answer question below:  Bayo: Wao! Shola, how did you manage to purchase a new tricycle?  Shola: I did not buy it, it was the Councillor from my town that distributed tricycles to unemployed youths. I am lucky to be one of them.  Bayo: Congratulation! That's a good gesture. I wish the Councillor from my town would do same.  Shola in the dialogue above will likely end up being","images":[],"options":{"A":"patriotic","B":"hard working","C":"contended","D":"self-reliant"},"answer":"D","explanation":"Given that Shola has received a tricycle, he now has a means to earn a living and thus, he is likely to become self-reliant. Self-reliance is the ability to depend on oneself for the things one needs. In this case, Shola can use the tricycle for transportation services and earn income, reducing his dependence on others.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>33","subject":"Civic Education","year":"2020","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : DIFFERENT CULT GROUPS IN NIGERIA AND THEIR SYMBOLS","question":"Which of the following is a known as cult group in Nigeria?","images":[],"options":{"A":"Rangers","B":"Pirates","C":"Flamingoes","D":"Illuminatis"},"answer":"B","explanation":"A cult group is a social group that is defined by its unusual religious, spiritual, or philosophical beliefs, or by its common interest in a particular personality, object, or goal. In Nigeria, the Pirates is a known cult group. Therefore, the correct answer is option 2.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2020>34","subject":"Civic Education","year":"2020","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : GOVERNMENT AGENCIES WORKING TO PREVENT DRUG ABUSE/TRAFFICKING AND THEIR ACTIVITIES","question":"The body in charge of controlling trafficking of drugs in Nigeria is the","images":[],"options":{"A":"Federal Road Safety Corps (FRSC)","B":"National Agency For Food and Drug Administration and Control (NAFDAC)","C":"National Drug Law Enforcement Agency (NDLEA)","D":"Nigerian Institute Of Medical Research (NIMR)"},"answer":"C","explanation":"The National Drug Law Enforcement Agency (NDLEA) is a Federal agency in Nigeria charged with eliminating the growing, processing, manufacturing, selling, exporting, and trafficking of hard drugs. Therefore, the correct answer is option 3.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2020>35","subject":"Civic Education","year":"2020","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : ACHIEVING POPULAR PARTICIPATION IN POLITICS","question":"Which of the following makes the votes of the poor and the rich equal?","images":[],"options":{"A":"Compulsory voting","B":"Right to vote","C":"Popular participation","D":"Free and fair election"},"answer":"D","explanation":"The votes of the poor and the rich are made equal through a free and fair election. This is because in a free and fair election, every vote counts equally regardless of the voter's social or economic status. The concept of a free and fair election is a fundamental aspect of democracy, where each citizen has the right to vote and their vote has equal weight.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2020>36","subject":"Civic Education","year":"2020","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : MEANING OF HUMAN TRAFFICKING","question":"The act of recruiting and trading of persons for the purpose of commercial exploitation is known as","images":[],"options":{"A":"slave trade","B":"human trafficking","C":"human rights abuse","D":"amnesty violations"},"answer":"B","explanation":"Human trafficking is the act of recruiting and trading of persons for the purpose of commercial exploitation. This involves the use of force, fraud, or coercion to obtain some type of labor or commercial sex act. It is a serious crime and a grave violation of human rights.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2020>37","subject":"Civic Education","year":"2020","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PROBLEMS OF RULE OF LAW","question":"Which of these is an disadvantage to the application of the rule of law in a democratic society?","images":[],"options":{"A":"Existence of free and fair election","B":"Granting of immunity to public office holders","C":"Ensuring equal protection of citizen's rights","D":"Promoting popular participation in politics"},"answer":"B","explanation":"The rule of law is a principle that ensures that all individuals, including public office holders, are subject to the law and can be held accountable for their actions. However, when public office holders are granted immunity, they are protected from legal proceedings for actions taken in their official capacity. This can be seen as a disadvantage to the application of the rule of law in a democratic society, as it can potentially allow for abuse of power and corruption without fear of legal repercussions.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>38","subject":"Civic Education","year":"2020","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : FEATURES OF RULE OF LAW","question":"Use the features of democracy below to answer question below:    I.   Rule of law  II. Judicial independence  III. Press Freedom  IV. Official opposition  V. Free,fair and periodic election  VI. Universal adult suffrage    The protection of citizens' right can be best guaranteed when there is","images":[],"options":{"A":"II and V","B":"III and VI","C":"I and II","D":"IV and V"},"answer":"C","explanation":"The protection of citizens' rights can be best guaranteed when there is Rule of Law (I) and Judicial Independence (II). The rule of law ensures that all citizens are treated equally under the law, and judicial independence ensures that the judiciary can make decisions free from influence or pressure from other branches of government. This combination helps to ensure that citizens' rights are protected and that justice is served fairly and impartially.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>39","subject":"Civic Education","year":"2020","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PILLARS OF DEMOCRACY","question":"Use the features of democracy below to answer question below:    I.   Rule of law  II. Judicial independence  III. Press Freedom  IV. Official opposition  V. Free,fair and periodic election  VI. Universal adult suffrage  Constructive criticism of government policies and action in a democratic state is best promoted by","images":[],"options":{"A":"I and V","B":"IV and VI","C":"III and IV","D":"V and VI"},"answer":"C","explanation":"Constructive criticism of government policies and action in a democratic state is best promoted by Press Freedom and Official opposition. Press Freedom allows the media to report and critique government actions without fear of retribution, promoting transparency and accountability. Official opposition provides a platform for alternative viewpoints and policies, encouraging debate and scrutiny of government actions.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>40","subject":"Civic Education","year":"2020","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC","question":"Use the features of democracy below to answer question below:    I.   Rule of law  II. Judicial independence  III. Press Freedom  IV. Official opposition  V. Free,fair and periodic election  VI. Universal adult suffrage  Smooth transition of government in a democratic state is ensured when there is","images":[],"options":{"A":"I and III","B":"III and VI","C":"III and IV","D":"V and VI"},"answer":"D","explanation":"Smooth transition of government in a democratic state is ensured when there is Free, fair and periodic election and Universal adult suffrage. Free, fair and periodic elections ensure that power is transferred peacefully from one government to another. Universal adult suffrage guarantees that all adult citizens have the right to vote, ensuring that the transition of power is based on the will of the people.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>41","subject":"Civic Education","year":"2020","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT","question":"The 1999 constitution could be described as rigid mainly because","images":[],"options":{"A":"its amendment requires two-third majority votes of the National Assembly","B":"its implementation requires the regular services of experienced constitutional lawyers","C":"adherence to its provision is very difficult","D":"it requires the presidential proclamation and judicial decision"},"answer":"A","explanation":"The 1999 constitution of Nigeria is described as rigid because its amendment requires a two-third majority vote of the National Assembly. This means that for any change to be made to the constitution, it must be approved by a significant majority of the legislative body, making it difficult to alter. This is a characteristic of a rigid constitution.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>42","subject":"Civic Education","year":"2020","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : ACHIEVING POPULAR PARTICIPATION IN POLITICS","question":"One major factor that hinders women from participating actively in politics is","images":[],"options":{"A":"their educational background","B":"lack of fund and financial power","C":"societal discrimination and belief system","D":"their religious background"},"answer":"C","explanation":"Societal discrimination and belief system is a major factor that hinders women from participating actively in politics. In many societies, women are seen as inferior and are not given equal opportunities as men in many areas including politics. This societal belief and discrimination limit their participation in politics.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>43","subject":"Civic Education","year":"2020","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC","question":"Under the 1999 Nigerian constitution, the judiciary exercises the greatest power of checks and balances over the","images":[],"options":{"A":"Executive and Legislature","B":"House of Representative and Senate","C":"Local Government Councils and The State Houses of Assembly","D":"States legislature and National Assembly"},"answer":"A","explanation":"The judiciary in Nigeria, as per the 1999 constitution, exercises the greatest power of checks and balances over the Executive and Legislature. This is because the judiciary has the power to interpret the constitution and the laws of the land. It can declare actions of the executive and laws of the legislature unconstitutional if they violate any part of the constitution. This power of judicial review gives the judiciary a significant role in checking and balancing the other two arms of government.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>44","subject":"Civic Education","year":"2020","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM","question":"The activities of Economic and Financial Crime Commission (EFCC) can help in promoting the following except","images":[],"options":{"A":"development","B":"democracy","C":"justice","D":"dictatorship"},"answer":"D","explanation":"The Economic and Financial Crime Commission (EFCC) is a Nigerian law enforcement agency that investigates financial crimes such as advance fee fraud and money laundering. The activities of EFCC promote development, democracy, and justice by ensuring that economic and financial crimes are investigated and prosecuted. However, these activities do not promote dictatorship. Dictatorship is a form of government where a single person or a small group possesses absolute power without effective constitutional limitations. EFCC's activities are aimed at promoting transparency and accountability, which are contrary to the principles of a dictatorship.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>45","subject":"Civic Education","year":"2020","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS","question":"Use the cartoon in Figure 2 to answer questions below      Based on the cartoon in Figure 2, it is evident that fuel scarcity is associated with the following except","images":["data:image/png;base64,"],"options":{"A":"corruption in public corporation driven oil sector","B":"the inability of fuel marketers to supply fuel","C":"corruption in private corporation driven oil sector","D":"adequate importation of petrol by licensed marketers"},"answer":"D","explanation":"Fuel scarcity is associated with corruption in public corporation driven oil sector, the inability of fuel marketers to supply fuel, corruption in private corporation driven oil sector.","marks":"1","difficulty":"3"},{"id":"objective>Civic Education>2020>46","subject":"Civic Education","year":"2020","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF POPULAR PARTICIPATION","question":"Use the cartoon in Figure 2 to answer questions below    In Figure 2, the statement  \"government has started the war on corruption\" is an indication that","images":["data:image/png;base64,"],"options":{"A":"taxi drivers are not happy with the new fuel price","B":"the patronage of taxi has reduced","C":"government is now tackling a major civic problem","D":"corruption has been eradicated in the oil sector"},"answer":"C","explanation":"The statement indicates that government is now tackling a major civic problem.","marks":"1","difficulty":"3"},{"id":"objective>Civic Education>2020>47","subject":"Civic Education","year":"2020","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : MEANING OF POLITICAL APATHY","question":"The feeling of indifference people have towards participating in issues relating to governance is termed","images":[],"options":{"A":"political discontentment","B":"apathy","C":"bad leadership","D":"selfishness"},"answer":"B","explanation":"Apathy is the term used to describe a state of indifference, or the suppression of emotions such as concern, excitement, motivation, or passion. In the context of governance, political apathy refers to the indifference towards political activities such as elections, civil rights, and freedom of speech. It can manifest as a lack of interest in participating in politics, or a lack of belief in the importance of one's vote.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>48","subject":"Civic Education","year":"2020","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : PROBLEMS OF CIVIL SOCIETY; I.E. BRIBERY AND CORRUPTION, INADEQUATE FUNDING, THE OVERBEARING INFLUENCE OF FOREIGN DONORS ETC","question":"Which of the following is a negative way of engaging in popular participation in a state?","images":[],"options":{"A":"Engaging in  rallies and demonstration","B":"Joining political party of your choice","C":"Taking part in  general elections","D":"Snatching of ballot box during election"},"answer":"D","explanation":"Snatching of ballot box during election is a negative way of engaging in popular participation in a state. It is an act of electoral fraud and is illegal. It undermines the democratic process by preventing the votes from being counted accurately. The other options listed such as engaging in rallies and demonstrations, joining a political party of your choice, and taking part in general elections are all legitimate and positive ways of participating in the political process.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>49","subject":"Civic Education","year":"2020","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING, TYPES, AND FEATURES OF DEMOCRACY;","question":"Representative democracy thrives on","images":[],"options":{"A":"educated electorates","B":"formation of political parties","C":"free and fair elections","D":"equal gender representation"},"answer":"C","explanation":"Representative democracy thrives on free and fair elections. This is because in a representative democracy, citizens elect representatives to make laws and policies on their behalf. For this system to work effectively, elections must be free and fair to ensure that the elected representatives truly reflect the will of the people.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2020>50","subject":"Civic Education","year":"2020","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : PROBLEMS OF PUBLIC SERVICE","question":"Which of the the following is a major limitation to the operational effectiveness in the public service?","images":[],"options":{"A":"Change of government","B":"Corruption","C":"Nepotism","D":"Bureaucratic red-tapism"},"answer":"D","explanation":"Bureaucratic red-tapism is a major limitation to the operational effectiveness in the public service. Bureaucratic red-tapism refers to excessive regulation or rigid conformity to formal rules that is considered redundant or bureaucratic and hinders or prevents action or decision-making. This can lead to inefficiencies and delays in the public service.","marks":"1","difficulty":"2"}];